def replace_single_line_entry(text: str, msgid: str, msgstr: str) -> str:
    return text.replace(
        f'msgid "{msgid}"\nmsgstr "Provides the API behavior described by this entry."',
        f'msgid "{msgid}"\nmsgstr "{msgstr}"',
    ).replace(
        f'msgid "{msgid}"\nmsgstr "As."',
        f'msgid "{msgid}"\nmsgstr "{msgstr}"',
    ).replace(
        f'msgid "{msgid}"\nmsgstr "/."',
        f'msgid "{msgid}"\nmsgstr "{msgstr}"',
    ).replace(
        f'msgid "{msgid}"\nmsgstr "2D."',
        f'msgid "{msgid}"\nmsgstr "{msgstr}"',
    ).replace(
        f'msgid "{msgid}"\nmsgstr "3D."',
        f'msgid "{msgid}"\nmsgstr "{msgstr}"',
    )


def po_block_to_text(block: str) -> str:
    value = ""
    for line in block.splitlines():
        line = line.strip()
        if line.startswith('"'):
            value += ast.literal_eval(line)
    return value


def text_to_po_block(value: str) -> str:
    escaped = value.replace("\\", "\\\\").replace('"', '\\"')
    return f'"{escaped}"'


ENTRY_RE = re.compile(r'msgid ((?:"(?:\\.|[^"])*"\n?)+)msgstr ((?:"(?:\\.|[^"])*"\n?)+)')


def apply_overrides(text: str) -> str:
    def replace(match: re.Match[str]) -> str:
        msgid_block = match.group(1)
        msgstr_block = match.group(2)
        msgid = po_block_to_text(msgid_block)
        if msgid not in OVERRIDES:
            return match.group(0)
        return f"msgid {msgid_block}msgstr {text_to_po_block(OVERRIDES[msgid])}\n"

    return ENTRY_RE.sub(replace, text)


changed = []
for path in sorted(ROOT.glob("*.po")):
    text = path.read_text(encoding="utf-8")
    before = text
    for msgid, msgstr in OVERRIDES.items():
        text = replace_single_line_entry(text, msgid, msgstr)
    text = apply_overrides(text)
    text = re.sub(r'(")(#: )', r'\1\n\2', text)
    if text != before:
        path.write_text(text, encoding="utf-8")
        changed.append(path.as_posix())

for item in changed:
    print(item)
